import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic() {
        int[] result = new Solution().countingSort(new int[]{3, 1, 2, 1, 3, 2}, 1, 3);
        assertArrayEquals(new int[]{1, 1, 2, 2, 3, 3}, result);
    }

    @Test
    void singleElement() {
        // minVal == maxVal: only one bucket
        int[] result = new Solution().countingSort(new int[]{5}, 5, 5);
        assertArrayEquals(new int[]{5}, result);
    }

    @Test
    void empty() {
        int[] result = new Solution().countingSort(new int[]{}, 0, 9);
        assertArrayEquals(new int[]{}, result);
    }

    @Test
    void allSameValue() {
        // all elements map to the same bucket
        int[] result = new Solution().countingSort(new int[]{4, 4, 4, 4}, 2, 6);
        assertArrayEquals(new int[]{4, 4, 4, 4}, result);
    }

    @Test
    void alreadySorted() {
        int[] result = new Solution().countingSort(new int[]{1, 2, 3, 4, 5}, 1, 5);
        assertArrayEquals(new int[]{1, 2, 3, 4, 5}, result);
    }

    @Test
    void reverseSorted() {
        int[] result = new Solution().countingSort(new int[]{9, 7, 5, 3, 1}, 1, 9);
        assertArrayEquals(new int[]{1, 3, 5, 7, 9}, result);
    }

    @Test
    void largeDuplicatesSpread() {
        // values at the extremes of the range
        int[] result = new Solution().countingSort(new int[]{0, 100, 0, 100, 50}, 0, 100);
        assertArrayEquals(new int[]{0, 0, 50, 100, 100}, result);
    }
}
